import{_ as a,o as i,c as o,a2 as l}from"./chunks/framework.BuL2a98s.js";const h=JSON.parse('{"title":"Esquemático de la Tarjeta","description":"","frontmatter":{},"headers":[],"relativePath":"guide/esquematico.md","filePath":"guide/esquematico.md"}'),c={name:"guide/esquematico.md"};function t(s,e,n,r,d,u){return i(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="esquematico-de-la-tarjeta" tabindex="-1">Esquemático de la Tarjeta <a class="header-anchor" href="#esquematico-de-la-tarjeta" aria-label="Permalink to &quot;Esquemático de la Tarjeta&quot;">​</a></h1><p>El curso incluye el esquemático de referencia de la Tang Nano 9K para revisar conexiónes fisicas antes de cambiar un <code>pins.cst</code> o conectar hardware externo.</p><h2 id="archivo" tabindex="-1">Archivo <a class="header-anchor" href="#archivo" aria-label="Permalink to &quot;Archivo&quot;">​</a></h2><ul><li><a href="/unit_devlab_fpga_examples/guide/Tang_Nano_9k_3672_Schematic.pdf">Abrir esquemático Tang Nano 9K</a></li></ul><h2 id="para-que-usarlo" tabindex="-1">Para Qué Usarlo <a class="header-anchor" href="#para-que-usarlo" aria-label="Permalink to &quot;Para Qué Usarlo&quot;">​</a></h2><p>Usa el esquemático cuando necesites confirmar:</p><ul><li>Que pin físico corresponde a un LED, botón, reloj o conector.</li><li>Que banco de la FPGA alimenta una señal.</li><li>Que voltaje corresponde al <code>IO_TYPE</code> usado en el <code>.cst</code>.</li><li>Si una señal es activa en alto o activa en bajo.</li><li>Si un botón o entrada necesita <code>PULL_MODE=UP</code>.</li></ul><h2 id="relacion-con-pins-cst" tabindex="-1">Relación con <code>pins.cst</code> <a class="header-anchor" href="#relacion-con-pins-cst" aria-label="Permalink to &quot;Relación con `pins.cst`&quot;">​</a></h2><p>El esquemático muestra la conexión electrica real de la tarjeta. El archivo <code>pins.cst</code> traduce esa conexión a restricciones para el toolchain Gowin.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HDL top port  -&gt;  pins.cst  -&gt;  pin FPGA  -&gt;  circuito en esquemático</span></span></code></pre></div><p>Ejemplo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IO_LOC &quot;clk&quot; 52;</span></span>\n<span class="line"><span>IO_PORT &quot;clk&quot; IO_TYPE=LVCMOS33;</span></span></code></pre></div><p>En este caso el puerto HDL <code>clk</code> queda asignado al pin físico 52. Antes de usarlo en otro diseño, confirma en el esquemático que ese pin corresponde al reloj de la tarjeta y que el banco usa el voltaje esperado.</p><h2 id="checklist-al-cambiar-pines" tabindex="-1">Checklist al Cambiar Pines <a class="header-anchor" href="#checklist-al-cambiar-pines" aria-label="Permalink to &quot;Checklist al Cambiar Pines&quot;">​</a></h2><ol><li>Localiza el recurso en el esquemático: LED, botón, conector o reloj.</li><li>Anota el pin físico de la FPGA.</li><li>Revisa el voltaje del banco.</li><li>Actualiza <code>IO_LOC</code> con el número de pin.</li><li>Actualiza <code>IO_TYPE</code> con el estándar eléctrico correcto.</li><li>Usa sufijo <code>_n</code> si la señal es activa en bajo.</li><li>Compila con <code>devlab build</code> antes de cargar en placa.</li></ol><h2 id="referencias-del-curso" tabindex="-1">Referencias del Curso <a class="header-anchor" href="#referencias-del-curso" aria-label="Permalink to &quot;Referencias del Curso&quot;">​</a></h2><ul><li><a href="./cst">Archivos CST</a></li><li><a href="./curso">Ruta del curso</a></li><li><a href="./../examples/digital-labs/">Digital Labs</a></li></ul>',17)])])}const m=a(c,[["render",t]]);export{h as __pageData,m as default};
